sed -i 's/<div style="padding: 1rem; background: var(--bg-body); border-radius: var(--radius-md); border-left: 3px solid var(--warning);">/<div style="padding: 1.25rem; background: var(--bg-card-hover); border-radius: var(--radius-md); border-left: 4px solid var(--warning); display: flex; flex-direction: column; gap: 0.5rem; transition: background 0.2s ease; cursor: pointer;" onmouseover="this.style.background='\''var(--border-color)'\'';" onmouseout="this.style.background='\''var(--bg-card-hover)'\'';">/g' js/app.js
sed -i 's/<strong>Estoque Baixo<\/strong>/<div style="display: flex; align-items: center; gap: 0.5rem; color: var(--text-primary); font-weight: 600; font-size: 0.95rem;"><i class="fa-solid fa-triangle-exclamation" style="color: var(--warning);"><\/i> Estoque Baixo<\/div>/g' js/app.js
sed -i 's/<p style="margin: 0.25rem 0 0 0; font-size: 0.85rem; color: var(--text-secondary);">${p.name} (Restam: ${p.stock})<\/p>/<p style="margin: 0; font-size: 0.85rem; color: var(--text-secondary);">${p.name} (Restam: ${p.stock})<\/p>/g' js/app.js
